2	import { getProject } from './project.js';
3	
4	const VALID_STATUSES = ['todo', 'in_progress', 'review', 'done', 'cancelled'];
5	const VALID_PRIORITIES = ['low', 'medium', 'high', 'urgent'];
6	
7	export function createTask({ title, projectId, assigneeId = null, priority = 'medium', description = '' }) {
8	  if (!title?.trim()) {
9	    throw Object.assign(new Error('Task title is required'), { status: 400 });
10	  }
11	  if (!projectId) {
12	    throw Object.assign(new Error('Project ID is required'), { status: 400 });
13	  }
14	
15	  getProject(projectId);
16	
17	  if (!VALID_PRIORITIES.includes(priority)) {
18	    throw Object.assign(new Error(`Invalid priority: ${priority}`), { status: 400 });
19	  }
20	
21	  const tasks = getCollection('tasks');
22	  const id = generateId('task');
23	  const task = {
24	    id,
25	    title: title.trim(),
26	    description,
27	    projectId,
28	    assigneeId,
29	    status: 'todo',
30	    priority,
31	    tags: [],
32	    createdAt: new Date().toISOString(),
33	    updatedAt: new Date().toISOString(),
34	  };
35	
36	  tasks.set(id, task);
37	  return task;
38	}
39	
40	export function getTask(id) {
41	  const task = getCollection('tasks').get(id);
42	  if (!task) {
43	    throw Object.assign(new Error(`Task ${id} not found`), { status: 404 });
44	  }
45	  return task;
46	}
47	
48	export function listTasks({ projectId, assigneeId, status, priority, page = 1, limit = 20 } = {}) {
49	  let results = [...getCollection('tasks').values()];
50	
51	  if (projectId) results = results.filter(t => t.projectId === projectId);
52	  if (assigneeId) results = results.filter(t => t.assigneeId === assigneeId);
53	  if (status) results = results.filter(t => t.status === status);
54	  if (priority) results = results.filter(t => t.priority === priority);
55	
56	  const total = results.length;
57	  const start = (page - 1) * limit;
58	  return { data: results.slice(start, start + limit), total, page, limit };
59	}
60	
61	export function updateTask(id, updates) {
62	  const task = getTask(id);
63	
64	  if (updates.status && !VALID_STATUSES.includes(updates.status)) {
65	    throw Object.assign(new Error(`Invalid status: ${updates.status}`), { status: 400 });
66	  }
67	  if (updates.priority && !VALID_PRIORITIES.includes(updates.priority)) {
68	    throw Object.assign(new Error(`Invalid priority: ${updates.priority}`), { status: 400 });
69	  }
70	
71	  const allowed = ['title', 'description', 'assigneeId', 'status', 'priority', 'tags'];
72	  for (const key of allowed) {
73	    if (updates[key] !== undefined) {
74	      task[key] = updates[key];
75	    }
76	  }
77	
78	  task.updatedAt = new Date().toISOString();
79	  return task;
80	}
81	
82	export function deleteTask(id) {
83	  const task = getTask(id);
84	  getCollection('tasks').delete(id);
85	  return task;
86	}
87	"}
