import taskRoutes from './routes/tasks.js';
import userRoutes from './routes/users.js';

const app = express();
const PORT = process.env.PORT || 3000;

// MIDDLEWARE (in order):
1. app.use(express.json({ limit: '1mb' }));     // JSON parser with 1MB limit
2. app.use(requestLogger);                        // Custom logging middleware

