  filter1, filter2, ...,  // Optional filters
  page = 1,               // Default: 1
  limit = 20              // Default: 20
}) → { data: array, total: number, page: number, limit: number }
```

#### Route Handler Pattern (Exception Handling):
```javascript
// For operations that can throw:
router.post('/', (req, res, next) => {
  try {
    const result = createResource(req.body);
    res.status(201).json(result);
  } catch (err) {
    next(err);  // Pass to error middleware
  }
});

// For read-only operations (list endpoints):
router.get('/', (req, res) => {
  const result = listResource(req.query);
  res.json(result);  // No error handling needed
});
```

#### Update Pattern:
```javascript
updateResource(id, updates) {
  const resource = getResource(id);  // Throws 404 if not found

  // Validate any enum fields
  if (updates.field && !VALID_VALUES.includes(updates.field)) {
    throw Object.assign(new Error('Invalid field'), { status: 400 });
  }

  // Only update allowed fields
  const allowed = ['field1', 'field2'];
  for (const key of allowed) {
    if (updates[key] !== undefined) {
      resource[key] = updates[key];
    }
  }

  // Update timestamp
  resource.updatedAt = new Date().toISOString();
  return resource;
}
```

#### Cascading Delete Pattern:
When deleting a parent resource, delete all child resources:
```javascript
deleteProject(id) {
  const project = getProject(id);
  getCollection('projects').delete(id);

  // Delete all children
  const tasks = getCollection('tasks');
  for (const [taskId, task] of tasks) {
    if (task.projectId === id) tasks.delete(taskId);
  }

  return project;
}
```

#### Response Status Conventions:
- `201` - Resource created (POST)
- `200` - Success (GET, PATCH)
- `204` - Success with no content (DELETE)
- `400` - Bad request (validation errors)
- `404` - Not found
- `409` - Conflict (duplicate unique field)
- `500` - Server error

#### JSON Request/Response:
- All endpoints accept/return JSON
- JSON parser configured with 1MB limit
- All errors returned as `{ error: "message" }`
- All successful responses return the resource object or collection with metadata

