const STOP_WORDS = new Set([
  'the', 'a', 'an', 'is', 'at', 'in', 'on', 'to', 'of', 'and', 'or', 'it',
  'for', 'with', 'as', 'by', 'this', 'that', 'from', 'be', 'are', 'was',
  'were', 'has', 'have', 'had', 'do', 'does', 'did', 'but', 'not', 'so',
  'if', 'no', 'can', 'will', 'just', 'should', 'now',
]);

const FIELD_WEIGHTS = { title: 3, description: 1, tags: 2 };

function tokenize(text) {
  if (!text || typeof text !== 'string') return [];
  return text
    .toLowerCase()
    .split(/[\s\p{P}]+/u)
    .filter(t => t.length > 0 && !STOP_WORDS.has(t));
}

function escapeHtml(str) {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;');
}

function highlightText(text, queryTokens) {
  if (!text || typeof text !== 'string') return '';
  const escaped = escapeHtml(text);
  if (queryTokens.length === 0) return escaped;

  const pattern = queryTokens
    .map(t => t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'))
    .join('|');
  const regex = new RegExp(`(${pattern})`, 'gi');
  return escaped.replace(regex, '<mark>$1</mark>');
}

function scoreTask(task, queryTokens) {
  if (queryTokens.length === 0) return 0;

  let score = 0;
  const titleTokens = tokenize(task.title);
  const descTokens = tokenize(task.description);
  const tagTokens = (task.tags || []).map(t => t.toLowerCase());

  for (const qt of queryTokens) {
    const titleCount = titleTokens.filter(t => t.includes(qt)).length;
    score += titleCount * FIELD_WEIGHTS.title;

    const descCount = descTokens.filter(t => t.includes(qt)).length;
    score += descCount * FIELD_WEIGHTS.description;

    const tagCount = tagTokens.filter(t => t.includes(qt)).length;
    score += tagCount * FIELD_WEIGHTS.tags;
  }

  return score;
}

export function search({ q, projectId, type, page = 1, limit = 20 } = {}) {
  if (!q || !q.trim()) {
    throw Object.assign(new Error('Search query is required'), { status: 400 });
  }

  const queryTokens = tokenize(q);
  if (queryTokens.length === 0) {
    return { query: q, results: [], total: 0, page, limit };
  }

  const tasks = [...getCollection('tasks').values()];
  let candidates = tasks;

  if (projectId) {
    candidates = candidates.filter(t => t.projectId === projectId);
  }
  if (type && type !== 'task') {
    return { query: q, results: [], total: 0, page, limit };
  }

  const scored = [];
  for (const task of candidates) {
    const score = scoreTask(task, queryTokens);
    if (score > 0) {
      scored.push({ task, score });
    }
  }

  scored.sort((a, b) => b.score - a.score);

  const total = scored.length;
  const start = (page - 1) * limit;
  const pageResults = scored.slice(start, start + limit);

  const results = pageResults.map(({ task, score }) => ({
    type: 'task',
    id: task.id,
    score,
    highlights: {
      title: highlightText(task.title, queryTokens),
      description: highlightText(task.description, queryTokens),
    },
    data: task,
  }));

  return { query: q, results, total, page, limit };
}
