  }

  if (path === '/api/users') {
    if (m === 'POST') return { resource: 'users', action: 'create' };
    if (m === 'GET') return { resource: 'users', action: 'list' };
  }

  return null;
}

function executeOperation(method, path, body) {
  const route = resolveRoute(method, path);
  if (!route) {
    throw Object.assign(new Error(`Route ${method} ${path} not found`), { status: 404 });
  }

  const { resource, action, id } = route;

  if (resource === 'projects') {
    if (action === 'create') return { status: 201, data: createProject(body || {}) };
    if (action === 'get') return { status: 200, data: getProject(id) };
    if (action === 'list') return { status: 200, data: listProjects(body || {}) };
    if (action === 'update') return { status: 200, data: updateProject(id, body || {}) };
    if (action === 'delete') { deleteProject(id); return { status: 204, data: null }; }
    if (action === 'addMember') {
      if (!body?.userId) throw Object.assign(new Error('userId is required'), { status: 400 });
      return { status: 200, data: addMember(id, body.userId) };
    }
  }

  if (resource === 'tasks') {
    if (action === 'create') return { status: 201, data: createTask(body || {}) };
    if (action === 'get') return { status: 200, data: getTask(id) };
    if (action === 'list') return { status: 200, data: listTasks(body || {}) };
    if (action === 'update') return { status: 200, data: updateTask(id, body || {}) };
    if (action === 'delete') { deleteTask(id); return { status: 204, data: null }; }
  }

  if (resource === 'users') {
    if (action === 'create') return { status: 201, data: createUser(body || {}) };
    if (action === 'get') return { status: 200, data: getUser(id) };
    if (action === 'list') return { status: 200, data: listUsers(body || {}) };
  }
}

export function executeBatch({ operations, atomic = false } = {}) {
  if (!Array.isArray(operations)) {
    throw Object.assign(new Error('operations must be an array'), { status: 400 });
  }
  if (operations.length === 0) {
    throw Object.assign(new Error('operations array must not be empty'), { status: 400 });
  }
  if (operations.length > MAX_BATCH_SIZE) {
    throw Object.assign(
      new Error(`Batch size ${operations.length} exceeds maximum of ${MAX_BATCH_SIZE}`),
      { status: 400 }
    );
  }

  for (let i = 0; i < operations.length; i++) {
    const op = operations[i];
    if (!op.method || !op.path) {
      throw Object.assign(
        new Error(`Operation at index ${i} must have method and path`),
        { status: 400 }
      );
    }
  }

  const results = [];
  let succeeded = 0;
  let failed = 0;
  const snapshot = atomic ? snapshotStore() : null;

  for (let i = 0; i < operations.length; i++) {
    const { method, path, body } = operations[i];
    try {
      const result = executeOperation(method, path, body);
      results.push({ index: i, status: result.status, data: result.data });
      succeeded++;
    } catch (err) {
      const status = err.status || 500;
      const message = status === 500 ? 'Internal server error' : err.message;
      results.push({ index: i, status, data: null, error: message });
      failed++;

      if (atomic) {
        restoreStore(snapshot);
        return {
          results,
          succeeded: 0,
          failed: i + 1,
          total: operations.length,
        };
      }
    }
  }

  return { results, succeeded, failed, total: operations.length };
}
